A hybrid greedy-regret insertion with dynamic parameter tuning, fallback to cheapest feasible route creation, and iterative refinement through pairwise swap consideration.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx           int
		score         float64
		deltaCost     float64
		originalCost  float64
		valid         bool
	}
	for offset, ori := range oris {
		des := dess[offset]
		shipID := total_ship + offset
		candidates := make([]candidate, 0, dispatch.AssignsLen+1)
		fallbackIdx := -1
		minRawIncrease := 1e18
		for i := 0; i < dispatch.AssignsLen; i++ {
			prevCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if !ok {
				continue
			}
			dispatch.Assigns[i].GenRoute()
			newCost := dispatch.Assigns[i].Cost
			if newCost >= 0 && prevCost >= 0 {
				incr := newCost - prevCost
				if incr < minRawIncrease {
					minRawIncrease = incr
					fallbackIdx = i
				}
				slack := float64(dispatch.Assigns[i].StationCurrent.TimeEnd-dispatch.Assigns[i].StationCurrent.TimeStart+1)
				baseSlack := 1440.0
				normSlack := slack / baseSlack
				routeSz := float64(len(dispatch.Assigns[i].Stations))
				compactBonus := 1.0 / (routeSz + 1.0)
				wIncr := incr / (prevCost + 1e-9)
				score := wIncr - 0.25*normSlack + 0.05*compactBonus
				candidates = append(candidates, candidate{idx: i, score: score, deltaCost: incr, originalCost: prevCost, valid: true})
			}
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
		}
		inserted := false
		if len(candidates) > 0 {
			sortByScore := func(arr []candidate) {
				for s := 0; s < len(arr)-1; s++ {
					for t := s + 1; t < len(arr); t++ {
						if arr[s].score > arr[t].score {
							arr[s], arr[t] = arr[t], arr[s]
						}
					}
				}
			}
			sortByScore(candidates)
			bestC := candidates[0]
			regretVal := 0.0
			if len(candidates) > 1 {
				regretVal = candidates[1].score - bestC.score
			}
			thresholdRegret := 0.002
			selectedIdx := bestC.idx
			if regretVal > thresholdRegret {
				adjustedMin := bestC.score
				for _, c := range candidates {
					adjScore := c.score - 0.6*(float64(len(dispatch.Assigns[c.idx].Stations))/100.0)
					if adjScore < adjustedMin {
						adjustedMin = adjScore
						selectedIdx = c.idx
					}
				}
			}
			okTry := dispatch.Assigns[selectedIdx].AddShip(shipID, ori, des)
			if okTry {
				dispatch.Assigns[selectedIdx].GenRoute()
				if dispatch.Assigns[selectedIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[selectedIdx].RemoveShip(shipID)
					dispatch.Assigns[selectedIdx].GenRoute()
				}
			}
		}
		if !inserted {
			if fallbackIdx >= 0 {
				okF := dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
				if okF {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						inserted = true
					} else {
						dispatch.Assigns[fallbackIdx].RemoveShip(shipID)
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				ptr := &dispatch.Assigns[dispatch.AssignsLen]
				okNew := ptr.AddShip(shipID, ori, des)
				if okNew {
					ptr.GenRoute()
					if ptr.Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						ptr.RemoveShip(shipID)
						ptr.GenRoute()
					}
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				ptr := &dispatch.Assigns[dispatch.AssignsLen]
				okLast := ptr.AddShip(shipID, ori, des)
				if okLast {
					ptr.GenRoute()
					dispatch.AssignsLen++
					inserted = true
				}
			}
		}
		for i := 0; i < dispatch.AssignsLen && inserted; i++ {
			currStations := dispatch.Assigns[i].Stations
			if len(currStations) < 3 {
				continue
			}
			tempCost := dispatch.Assigns[i].Cost
			swapMade := false
			for a := 1; a < len(currStations)-1 && !swapMade; a++ {
				stA := currStations[a]
				for b := a + 1; b < len(currStations)-1 && !swapMade; b++ {
					stB := currStations[b]
					if stA.ReqCode == stB.ReqCode || stA.Load != stB.Load {
						continue
					}
					dispatch.Assigns[i].RemoveShip(a)
					dispatch.Assigns[i].RemoveShip(b)
					addBackA := dispatch.Assigns[i].AddShip(a, ori, des)
					addBackB := dispatch.Assigns[i].AddShip(b, ori, des)
					if !addBackA || !addBackB {
						dispatch.Assigns[i].GenRoute()
						dispatch.Assigns[i].Cost = tempCost
						break
					}
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 && dispatch.Assigns[i].Cost < tempCost {
						swapMade = true
					} else {
						dispatch.Assigns[i].RemoveShip(a)
						dispatch.Assigns[i].RemoveShip(b)
						dispatch.Assigns[i].AddShip(a, ori, des)
						dispatch.Assigns[i].AddShip(b, ori, des)
						dispatch.Assigns[i].GenRoute()
						dispatch.Assigns[i].Cost = tempCost
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

